+            message: format!("{header_key} is \"{val}\", expected \"{expected_value}\""),
+            elapsed_ms: 0,
+            http_status: None,
+            headers_captured: None,
+        },
+        None => VerifyLiveCheck {
+            id: id.to_string(),
+            description: description.to_string(),
+            severity,
+            passed: false,
+            message: format!("{header_key} header missing"),
+            elapsed_ms: 0,
